 43→// SliceFromMessage returns an OpenCode export transcript scoped to messages starting from
 44→// startMessageIndex. This is the OpenCode equivalent of transcript.SliceFromLine —
 45→// for OpenCode's JSON format, scoping is done by message index rather than line offset.
 46→// Returns the original data if startMessageIndex <= 0.
 47→// Returns nil, nil if startMessageIndex exceeds the number of messages.
 48→func SliceFromMessage(data []byte, startMessageIndex int) ([]byte, error) {
 49→	if len(data) == 0 || startMessageIndex <= 0 {
 50→		return data, nil
 51→	}
 52→
 53→	session, err := ParseExportSession(data)
 54→	if err != nil {
 55→		return nil, fmt.Errorf("failed to parse export session for slicing: %w", err)
 56→	}
 57→	if session == nil {
 58→		return nil, nil
 59→	}
 60→
 61→	if startMessageIndex >= len(session.Messages) {
 62→		return nil, nil
 63→	}
 64→
 65→	scoped := &ExportSession{
 66→		Info:     session.Info,
 67→		Messages: session.Messages[startMessageIndex:],
 68→	}
 69→
 70→	out, err := json.Marshal(scoped)
 71→	if err != nil {
 72→		return nil, fmt.Errorf("failed to marshal scoped session: %w", err)
 73→	}
 74→	return out, nil
 75→}
