148→func handleLifecycleTurnEnd(ctx context.Context, ag agent.Agent, event *agent.Event) error {
149→	logCtx := logging.WithAgent(logging.WithComponent(ctx, "lifecycle"), ag.Name())
150→	logging.Info(logCtx, "turn-end",
151→		slog.String("event", event.Type.String()),
152→		slog.String("session_id", event.SessionID),
153→		slog.String("session_ref", event.SessionRef),
154→	)
155→
156→	sessionID := event.SessionID
157→	if sessionID == "" {
158→		sessionID = unknownSessionID
159→	}
160→
161→	transcriptRef := event.SessionRef
162→	if transcriptRef == "" {
163→		return errors.New("transcript file not specified")
164→	}
165→	if !fileExists(transcriptRef) {
166→		return fmt.Errorf("transcript file not found: %s", transcriptRef)
167→	}
168→
169→	// Early check: bail out quickly if the repo has no commits yet.
170→	if repo, err := strategy.OpenRepository(ctx); err == nil && strategy.IsEmptyRepository(repo) {
171→		fmt.Fprintln(os.Stderr, "Entire: skipping checkpoint. Will activate after first commit.")
172→		return NewSilentError(strategy.ErrEmptyRepository)
173→	}
174→
175→	// Create session metadata directory
176→	sessionDir := paths.SessionMetadataDirFromSessionID(sessionID)
177→	sessionDirAbs, err := paths.AbsPath(ctx, sessionDir)
178→	if err != nil {
179→		sessionDirAbs = sessionDir
180→	}
181→	if err := os.MkdirAll(sessionDirAbs, 0o750); err != nil {
182→		return fmt.Errorf("failed to create session directory: %w", err)
183→	}
184→
185→	// If agent implements TranscriptPreparer, wait for transcript to be ready
186→	if preparer, ok := ag.(agent.TranscriptPreparer); ok {
187→		if err := preparer.PrepareTranscript(ctx, transcriptRef); err != nil {
188→			fmt.Fprintf(os.Stderr, "Warning: failed to prepare transcript: %v\n", err)
189→		}
190→	}
191→
192→	// Copy transcript to session directory
193→	transcriptData, err := ag.ReadTranscript(transcriptRef)
194→	if err != nil {
195→		return fmt.Errorf("failed to read transcript: %w", err)
196→	}
197→	logFile := filepath.Join(sessionDirAbs, paths.TranscriptFileName)

140→	_, err := a.fetchAndCacheExport(ctx, sessionID)
141→	return err
142→}
