144→// fetchAndCacheExport calls `opencode export <sessionID>` and writes the result
145→// to a temporary file. Returns the path to the temp file.
146→//
147→// Integration testing: Set ENTIRE_TEST_OPENCODE_MOCK_EXPORT=1 to skip the
148→// `opencode export` call and use pre-written mock data instead. Tests must
149→// pre-write the transcript file to .entire/tmp/<sessionID>.json before
150→// triggering the hook. See integration_test/hooks.go:SimulateOpenCodeTurnEnd.
151→func (a *OpenCodeAgent) fetchAndCacheExport(ctx context.Context, sessionID string) (string, error) {
152→	// Get worktree root for the temp directory
153→	repoRoot, err := paths.WorktreeRoot(ctx)
154→	if err != nil {
155→		repoRoot = "."
156→	}
157→
158→	tmpDir := filepath.Join(repoRoot, paths.EntireTmpDir)
159→	tmpFile := filepath.Join(tmpDir, sessionID+".json")
160→
161→	// Integration test mode: use pre-written mock file without calling opencode export
162→	if os.Getenv("ENTIRE_TEST_OPENCODE_MOCK_EXPORT") != "" {
163→		if _, err := os.Stat(tmpFile); err == nil {
164→			return tmpFile, nil
165→		}
166→		return "", fmt.Errorf("mock export file not found: %s (ENTIRE_TEST_OPENCODE_MOCK_EXPORT is set)", tmpFile)
167→	}
168→
169→	// Call opencode export to get the transcript (always refresh on each turn)
170→	data, err := runOpenCodeExport(ctx, sessionID)
171→	if err != nil {
172→		return "", fmt.Errorf("opencode export failed: %w", err)
173→	}
174→
175→	// Validate output is valid JSON before caching
176→	if !json.Valid(data) {
177→		return "", fmt.Errorf("opencode export returned invalid JSON (%d bytes)", len(data))
178→	}
179→
180→	// Write to temp directory under .entire
181→	if err := os.MkdirAll(tmpDir, 0o750); err != nil {
182→		return "", fmt.Errorf("failed to create temp dir: %w", err)
183→	}
184→
185→	if err := os.WriteFile(tmpFile, data, 0o600); err != nil {
186→		return "", fmt.Errorf("failed to write export file: %w", err)
187→	}
188→
189→	return tmpFile, nil
190→}
