func TestExtractFilePathFromInput(t *testing.T) {
	t.Parallel()

	tests := []struct {
		name  string
		input map[string]any
		want  string
	}{
		{name: "camelCase filePath (OpenCode native format)", input: map[string]any{"filePath": "/repo/main.go"}, want: "/repo/main.go"},
