func TestExtractFilePaths(t *testing.T) {
	t.Parallel()

	tests := []struct {
		name  string
		state *ToolState
		want  []string
	}{
		{
			name:  "camelCase filePath from input",
			state: &ToolState{Input: map[string]any{"filePath": "/repo/main.go"}},
			want:  []string{"/repo/main.go"},
		},
		{
			name:  "path key from input",
