			name: "metadata takes priority over input",
			state: &ToolState{
				Input: map[string]any{"filePath": "/input/file.go"},
				Metadata: &ToolStateMetadata{
					Files: []ToolFileInfo{
						{FilePath: "/meta/file.go"},
